function isArmstrong(num) {
  const n = Math.abs(num);
  const digits = String(n).length;
  let sum = 0;
  let temp = n;
  while (temp > 0) {
    const digit = temp % 10;
    sum += Math.pow(digit, digits);
    temp = Math.floor(temp / 10);
  }
  return sum === n;
}

function isArmstrongReduce(num) {
  const n = Math.abs(num);
  const digits = String(n).length;
  return String(n).split('').reduce((sum, d) =>
    sum + Math.pow(+d, digits), 0) === n;
}
